package com.gov.moodleapp.presentation.dashboard

import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.example.moodlegovapp.core.data.repository.CoursesRepository
import com.example.moodlegovapp.core.data.repository.NotificationsRepository
import com.example.moodlegovapp.core.data.repository.UserRepository
import com.example.moodlegovapp.core.data.network.AppResult
import com.example.moodlegovapp.core.domain.models.Course
import com.example.moodlegovapp.core.domain.models.PerformanceOverview
import com.example.moodlegovapp.core.domain.models.TrainingStats
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.launch

data class DashboardUiState(
    val isLoading: Boolean = false,
    val courses: List<Course> = emptyList(),
    val performanceOverview: PerformanceOverview? = null,
    val trainingStats: TrainingStats? = null,
    val notificationCount: Int = 0,
    val error: String? = null
)

class DashboardViewModel(
    private val userRepository: UserRepository,
    private val coursesRepository: CoursesRepository,
    private val notificationsRepository: NotificationsRepository
) : ViewModel() {

    private val _uiState = MutableStateFlow(DashboardUiState())
    val uiState: StateFlow<DashboardUiState> = _uiState

    init {
        loadDashboardData()
    }

    private fun loadDashboardData() {
        viewModelScope.launch {
            _uiState.value = DashboardUiState(isLoading = true)

            try {
                val coursesResult = coursesRepository.getEnrolledCourses()
                val performanceResult = userRepository.getPerformanceOverview()
                val statsResult = userRepository.getTrainingStats()
                val notificationsResult = notificationsRepository.getNotifications()

                val courses = if (coursesResult is AppResult.Success) coursesResult.data else emptyList()
                val performance = if (performanceResult is AppResult.Success) performanceResult.data else null
                val stats = if (statsResult is AppResult.Success) statsResult.data else null
                val notificationCount = if (notificationsResult is AppResult.Success) notificationsResult.data.size else 0

                _uiState.value = DashboardUiState(
                    courses = courses,
                    performanceOverview = performance,
                    trainingStats = stats,
                    notificationCount = notificationCount
                )
            } catch (e: Exception) {
                _uiState.value = DashboardUiState(error = e.message)
            }
        }
    }

    fun refreshDashboard() {
        loadDashboardData()
    }
}

package com.gov.moodleapp.presentation.notifications

import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.example.moodlegovapp.core.data.repository.NotificationsRepository
import com.example.moodlegovapp.core.data.network.AppResult
import com.example.moodlegovapp.core.domain.models.Notification
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.launch

data class NotificationsUiState(
    val isLoading: Boolean = false,
    val notifications: List<Notification> = emptyList(),
    val error: String? = null
)

class NotificationsViewModel(
    private val notificationsRepository: NotificationsRepository
) : ViewModel() {

    private val _uiState = MutableStateFlow(NotificationsUiState())
    val uiState: StateFlow<NotificationsUiState> = _uiState

    init {
        loadNotifications()
    }

    private fun loadNotifications() {
        viewModelScope.launch {
            _uiState.value = NotificationsUiState(isLoading = true)
            val result = notificationsRepository.getNotifications()

            when (result) {
                is AppResult.Success -> {
                    _uiState.value = NotificationsUiState(notifications = result.data)
                }
                is AppResult.Failure -> {
                    _uiState.value = NotificationsUiState(error = result.error.toString())
                }
                is AppResult.Loading -> {
                    _uiState.value = NotificationsUiState(isLoading = true)
                }
            }
        }
    }

    fun markAsRead(notificationId: Int) {
        viewModelScope.launch {
            notificationsRepository.markAsRead(notificationId)
            loadNotifications()
        }
    }

    fun refreshNotifications() {
        loadNotifications()
    }
}
